/** Synced from backend/mock for offline fetch fallback. */
export const EMBEDDED_QUIZ = {"title":"Đề ôn giả lập — THPT QG Tiếng Anh (định hướng 2026)","questions":[{"id":"q1","text":"Choose the word whose underlined part differs from the others in pronunciation: A. ch**ea**p  B. r**ea**ch  C. br**ea**d  D. m**ea**t","options":["cheap","reach","bread","meat"],"correctIndex":2,"hint":"ea trong \"bread\" đọc /e/; các từ còn lại thường /iː/ (cheap, reach, meat)."},{"id":"q2","text":"Choose the word that differs from the others in the position of the main stress: A. **com**pete  B. **at**tract  C. **re**duce  D. **pro**gress (n.)","options":["compete","attract","reduce","progress"],"correctIndex":3,"hint":"\"progress\" (danh từ) nhấn âm đầu PRO-; ba từ kia thường nhấn âm thứ hai."},{"id":"q3","text":"She _______ working here since she graduated from university.","options":["has been","was","had been","is"],"correctIndex":0,"hint":"Since + mốc quá khứ + hiện tại vẫn tiếp diễn → hiện tại hoàn thành tiếp diễn: has been + V-ing."},{"id":"q4","text":"The government is trying to _______ the use of renewable energy in rural areas.","options":["promote","prevent","reject","ignore"],"correctIndex":0,"hint":"Ngữ cảnh tích cực: khuyến khích năng lượng tái tạo → promote."},{"id":"q5","text":"I wish I _______ how to code when I was still in high school.","options":["learn","have learned","had learned","would learn"],"correctIndex":2,"hint":"Wish + điều ước trái với quá khứ (đã qua, không thể đổi) → wish + past perfect: had learned."},{"id":"q6","text":"Find the mistake: **Hardly** had we **arrived** at the station **when** the train **has** left.","options":["Hardly","arrived","when","has"],"correctIndex":3,"hint":"Hardly... when... (quá khứ): động từ sau \"when\" dùng quá khứ đơn → \"had left\" hoặc \"left\", không dùng \"has left\"."},{"id":"q7","text":"Read: \"Many towns now run recycling schemes where residents sort waste at home. Surveys show these programmes cut landfill use and raise local awareness.\" The passage is mainly about _______.","options":["how to build a solar panel at home","benefits of community recycling programmes","the history of plastic invention","ways to learn a foreign language quickly"],"correctIndex":1,"hint":"Câu chủ đề: chương trình tái chế ở cộng đồng → giảm rác thải, nâng cao ý thức → chọn ý về lợi ích recycling."},{"id":"q8","text":"Complete: By June next year, she _______ her national voluntary service.","options":["will finish","will have finished","finishes","has finished"],"correctIndex":1,"hint":"By + mốc tương lai → future perfect: will have + V3."},{"id":"q9","text":"Choose the best synonym for \"**sustainable**\" in: \"We need a sustainable model for tourism.\"","options":["short-term","environmentally balanced / long-term viable","expensive","temporary"],"correctIndex":1,"hint":"Sustainable ≈ bền vững, có thể duy trì lâu dài mà không cạn kiệt tài nguyên."},{"id":"q10","text":"He suggested that she _______ a gap year before entering university.","options":["take","takes","took","taking"],"correctIndex":0,"hint":"Suggest + that + S + (should) + V0 → \"take\" (subjunctive / bare infinitive)."},{"id":"q11","text":"Choose the word whose underlined part differs: A. m**a**chine  B. ch**a**nge  C. l**a**zy  D. p**a**ge","options":["machine","change","lazy","page"],"correctIndex":0,"hint":"machine /ə/, change /eɪ/, lazy /eɪ/, page /eɪ/."},{"id":"q12","text":"Stress pattern: A. **ge**nerate  B. **con**tribute  C. **bi**ology  D. **ma**terial","options":["generate","contribute","biology","material"],"correctIndex":0,"hint":"generate nhấn 1, contribute nhấn 2, biology nhấn 2, material nhấn 2."},{"id":"q13","text":"If it _______ for the heavy rain, we would have finished the project on time.","options":["weren't","hasn't been","hadn't been","isn't"],"correctIndex":2,"hint":"Cấu trúc If it hadn't been for + N (điều kiện loại 3)."},{"id":"q14","text":"The new policy is expected to _______ significant changes in the education system.","options":["bring about","take off","look after","give up"],"correctIndex":0,"hint":"bring about = gây ra, dẫn đến."},{"id":"q15","text":"The man _______ you met yesterday is my uncle.","options":["who","whom","which","whose"],"correctIndex":1,"hint":"Whom dùng cho tân ngữ chỉ người."},{"id":"q16","text":"Find mistake: **Neither** the students **nor** their teacher **are** happy with the results.","options":["Neither","nor","are","results"],"correctIndex":2,"hint":"Neither A nor B: động từ chia theo B (teacher) → is."},{"id":"q17","text":"Synonym of \"**vital**\": \"Water is vital for all living organisms.\"","options":["unimportant","essential","expensive","optional"],"correctIndex":1,"hint":"vital = thiết yếu, quan trọng."},{"id":"q18","text":"I _______ my homework when the lights went out.","options":["did","was doing","have done","am doing"],"correctIndex":1,"hint":"Hành động đang xảy ra (was doing) thì hành động khác xen vào (went out)."},{"id":"q19","text":"Antonym of \"**compulsory**\": \"Is English a compulsory subject?\"","options":["optional","mandatory","required","necessary"],"correctIndex":0,"hint":"compulsory (bắt buộc) >< optional (tự chọn)."},{"id":"q20","text":"The more you practice, _______ you will become.","options":["the better","better","best","the best"],"correctIndex":0,"hint":"So sánh kép: The more... the better..."},{"id":"q21","text":"Pronunciation: A. n**o**te  B. v**o**te  C. gl**o**ve  D. h**o**pe","options":["note","vote","glove","hope"],"correctIndex":2,"hint":"glove /ʌ/, các từ khác /əʊ/."},{"id":"q22","text":"Stress pattern: A. **e**ducation  B. **u**niversity  C. **o**pportunity  D. **i**ntelligence","options":["education","university","opportunity","intelligence"],"correctIndex":3,"hint":"intelligence nhấn 2, các từ khác nhấn 3."},{"id":"q23","text":"I _______ you if I knew his phone number.","options":["will tell","would tell","told","tell"],"correctIndex":1,"hint":"Điều kiện loại 2 (trái với hiện tại)."},{"id":"q24","text":"The computer _______ was broken has been repaired.","options":["who","whom","whose","which"],"correctIndex":3,"hint":"Which dùng cho vật."},{"id":"q25","text":"He apologized _______ for the delay.","options":["to me","me","with me","for me"],"correctIndex":0,"hint":"apologize to somebody."},{"id":"q26","text":"Find mistake: The **children** were **playing** **happy** in the **garden**.","options":["children","playing","happy","garden"],"correctIndex":2,"hint":"Cần trạng từ happily bổ nghĩa cho động từ play."},{"id":"q27","text":"Synonym of \"**innovative**\": \"An innovative approach to learning.\"","options":["traditional","new","expensive","boring"],"correctIndex":1,"hint":"innovative = mới mẻ, sáng tạo."},{"id":"q28","text":"I _______ him since we were at school together.","options":["know","knew","have known","am knowing"],"correctIndex":2,"hint":"Hiện tại hoàn thành với since."},{"id":"q29","text":"Antonym of \"**vulnerable**\": \"Children are vulnerable to diseases.\"","options":["weak","safe","unprotected","exposed"],"correctIndex":1,"hint":"vulnerable (dễ bị tổn thương) >< safe (an toàn)."},{"id":"q30","text":"By the time we arrived, the movie _______.","options":["started","has started","had started","was starting"],"correctIndex":2,"hint":"Quá khứ hoàn thành cho hành động xảy ra trước 1 hành động quá khứ khác."},{"id":"q31","text":"Pronunciation: A. book**s**  B. pen**s**  C. dog**s**  D. boy**s**","options":["books","pens","dogs","boys"],"correctIndex":0,"hint":"books /s/, các từ khác /z/."},{"id":"q32","text":"Stress pattern: A. **fa**mous  B. **po**lite  C. **hap**py  & D. **qui**et","options":["famous","polite","happy","quiet"],"correctIndex":1,"hint":"polite nhấn 2, các từ khác nhấn 1."},{"id":"q33","text":"Unless you _______ harder, you won't pass the exam.","options":["study","don't study","studied","will study"],"correctIndex":0,"hint":"Unless = If not."},{"id":"q34","text":"She is looking _______ her lost cat.","options":["for","after","at","into"],"correctIndex":0,"hint":"look for = tìm kiếm."},{"id":"q35","text":"The girl _______ sister is my friend is beautiful.","options":["who","whom","whose","which"],"correctIndex":2,"hint":"Whose chỉ sở hữu."},{"id":"q36","text":"Find mistake: Every **student** **have** to **submit** their **assignment**.","options":["student","have","submit","assignment"],"correctIndex":1,"hint":"Every student + V số ít → has."},{"id":"q37","text":"Synonym of \"**resilient**\": \"The economy is resilient to shocks.\"","options":["weak","strong","fragile","unstable"],"correctIndex":1,"hint":"resilient = kiên cường, bền bỉ."},{"id":"q38","text":"He _______ to Paris three times this year.","options":["was","has been","had been","is"],"correctIndex":1,"hint":"Hiện tại hoàn thành cho trải nghiệm."},{"id":"q39","text":"Antonym of \"**prestigious**\": \"A prestigious university.\"","options":["famous","unknown","honorable","noted"],"correctIndex":1,"hint":"prestigious (danh tiếng) >< unknown (vô danh)."},{"id":"q40","text":"I _______ you if I had known the truth.","options":["will tell","would tell","would have told","told"],"correctIndex":2,"hint":"Điều kiện loại 3 (trái quá khứ)."}]};
export const EMBEDDED_FLASHCARD = {"title":"Flashcard — từ vựng ôn THPT QG Tiếng Anh (2026)","cards":[{"id":"c1","front":"curriculum","phonetic":"/kəˈrɪkjələm/","back":"chương trình giảng dạy / khung chương trình","hint":"Hay gặp trong đoạn về giáo dục."},{"id":"c2","front":"literacy","phonetic":"/ˈlɪtərəsi/","back":"khả năng đọc viết; trình độ học vấn cơ bản","hint":"Collocation: digital literacy."},{"id":"c3","front":"emission","phonetic":"/iˈmɪʃn/","back":"khí thải, sự phát ra (CO₂…)","hint":"Chủ đề môi trường / biến đổi khí hậu."},{"id":"c4","front":"biodiversity","phonetic":"/ˌbaɪəʊdaɪˈvɜːsəti/","back":"đa dạng sinh học","hint":"Danh từ ghép: bio + diversity."},{"id":"c5","front":"infrastructure","phonetic":"/ˈɪnfrəstrʌktʃə(r)/","back":"hạ tầng (giao thông, điện, internet…)","hint":"Đọc hiểu về phát triển kinh tế / đô thị."},{"id":"c6","front":"artificial intelligence","phonetic":"/ˌɑːtɪfɪʃl ɪnˈtelɪdʒəns/","back":"trí tuệ nhân tạo (AI)","hint":"Chủ đề công nghệ — paraphrase: machine learning."},{"id":"c7","front":"prejudice","phonetic":"/ˈpredʒudɪs/","back":"định kiến, thành kiến","hint":"Khác discrimination (phân biệt đối xử)."},{"id":"c8","front":"allocate","phonetic":"/ˈæləkeɪt/","back":"phân bổ, cấp (ngân sách, thời gian…)","hint":"Động từ trang trọng: allocate resources to…"},{"id":"c9","front":"implement","phonetic":"/ˈɪmplɪment/","back":"triển khai, thực hiện (chính sách, kế hoạch)","hint":"implement a policy / measure."},{"id":"c10","front":"mitigate","phonetic":"/ˈmɪtɪɡeɪt/","back":"làm giảm nhẹ, giảm thiểu (rủi ro, tác hại)","hint":"mitigate the effects of climate change."},{"id":"c11","front":"collaborate","phonetic":"/kəˈlæbəreɪt/","back":"cộng tác, hợp tác","hint":"collaborate with / on."},{"id":"c12","front":"ethical","phonetic":"/ˈeθɪkl/","back":"thuộc đạo đức, đạo lý","hint":"ethical issues in technology."},{"id":"c13","front":"sustainable","phonetic":"/səˈsteɪnəbl/","back":"bền vững","hint":"sustainable development / energy."},{"id":"c14","front":"innovation","phonetic":"/ˌɪnəˈveɪʃn/","back":"sự đổi mới, sáng kiến","hint":"technological innovation."},{"id":"c15","front":"vulnerable","phonetic":"/ˈvʌlnərəbl/","back":"dễ bị tổn thương","hint":"vulnerable to climate change / disease."},{"id":"c16","front":"preserve","phonetic":"/prɪˈzɜːv/","back":"bảo tồn, giữ gìn","hint":"preserve cultural heritage / environment."},{"id":"c17","front":"compulsory","phonetic":"/kəmˈpʌlsəri/","back":"bắt buộc","hint":"compulsory education / subjects."},{"id":"c18","front":"prestigious","phonetic":"/preˈstɪdʒəs/","back":"có uy tín, danh giá","hint":"a prestigious university / award."},{"id":"c19","front":"pioneer","phonetic":"/ˌpaɪəˈnɪə(r)/","back":"người tiên phong","hint":"a pioneer in the field of medicine."},{"id":"c20","front":"advocate","phonetic":"/ˈædvəkeɪt/","back":"ủng hộ, tán thành","hint":"advocate for human rights."},{"id":"c21","front":"consequence","phonetic":"/ˈkɒnsɪkwəns/","back":"hậu quả, hệ quả","hint":"face the consequences of actions."},{"id":"c22","front":"deteriorate","phonetic":"/dɪˈtɪəriəreɪt/","back":"xấu đi, suy yếu","hint":"health / relationship deteriorates."},{"id":"c23","front":"eliminate","phonetic":"/ɪˈlɪmɪneɪt/","back":"loại bỏ, xóa bỏ","hint":"eliminate poverty / discrimination."},{"id":"c24","front":"fluctuate","phonetic":"/ˈflʌktʃueɪt/","back":"dao động, biến động","hint":"prices / temperatures fluctuate."},{"id":"c25","front":"generate","phonetic":"/ˈdʒenəreɪt/","back":"tạo ra, phát ra","hint":"generate electricity / income."},{"id":"c26","front":"hazard","phonetic":"/ˈhæzəd/","back":"mối nguy hiểm","hint":"environmental / health hazard."},{"id":"c27","front":"incentive","phonetic":"/ɪnˈsentɪv/","back":"sự khuyến khích, động lực","hint":"financial incentive to work harder."},{"id":"c28","front":"jeopardize","phonetic":"/ˈdʒepədaɪz/","back":"gây nguy hiểm, hủy hoại","hint":"jeopardize a career / safety."},{"id":"c29","front":"knowledgeable","phonetic":"/ˈnɒlɪdʒəbl/","back":"có kiến thức, am hiểu","hint":"knowledgeable about a subject."},{"id":"c30","front":"legitimate","phonetic":"/lɪˈdʒɪtɪmət/","back":"hợp pháp, chính đáng","hint":"legitimate concern / claim."},{"id":"c31","front":"maintain","phonetic":"/meɪnˈteɪn/","back":"duy trì, bảo dưỡng","hint":"maintain a building / standard."},{"id":"c32","front":"negotiate","phonetic":"/nɪˈɡəʊʃieɪt/","back":"đàm phán, thương lượng","hint":"negotiate a contract / price."},{"id":"c33","front":"obstacle","phonetic":"/ˈɒbstəkl/","back":"trở ngại, chướng ngại vật","hint":"overcome an obstacle."},{"id":"c34","front":"potential","phonetic":"/pəˈtenʃl/","back":"tiềm năng","hint":"realize / fulfill potential."},{"id":"c35","front":"quantifiable","phonetic":"/ˈkwɒntɪfaɪəbl/","back":"có thể định lượng","hint":"quantifiable results / data."},{"id":"c36","front":"resilient","phonetic":"/rɪˈzɪliənt/","back":"kiên cường, mau phục hồi","hint":"resilient person / economy."},{"id":"c37","front":"stimulate","phonetic":"/ˈstɪmjuleɪt/","back":"kích thích, khuyến khích","hint":"stimulate the economy / brain."},{"id":"c38","front":"transform","phonetic":"/trænsˈfɔːm/","back":"thay đổi, biến đổi","hint":"transform a life / business."},{"id":"c39","front":"utilize","phonetic":"/ˈjuːtəlaɪz/","back":"tận dụng, sử dụng","hint":"utilize resources effectively."},{"id":"c40","front":"vital","phonetic":"/ˈvaɪtl/","back":"quan trọng, thiết yếu","hint":"vital role / part."}]};
export const EMBEDDED_SLIDE = {"_replace_note":"Slide ôn: cấu trúc đề, cách làm bài, từ vựng — bản giả lập THPT QG Tiếng Anh (định hướng 2026). Shape: title + slides[]. Viết câu đủ dài, hạn chế 'A: B' ngắn để theme friendly (tách tại dấu :) không bị trống.","title":"Ôn THPT QG Tiếng Anh — định hướng & cách làm bài (2026)","slides":[{"id":"s1","title":"Giới thiệu — Tổng quan kỳ thi","bullets":["Định hướng ôn 2026 — bộ slide giả lập giúp bạn lướt nhanh phân dạng và cách triển khai trong phòng thi.","Mục tiêu ôn tập — nắm rõ từng khối kiến thức, giữ nhịp làm bài ổn định và có chiến lược soát lỗi trước khi nộp bài.","Đề thi thường gồm 50 câu trắc nghiệm trong 60 phút; cần phân bổ thời gian hợp lý cho đọc hiểu dài và các câu suy luận.","Ưu tiên luyện theo chủ đề (ngữ pháp, từ vựng, đọc hiểu) rồi ghép thành đề tổng hợp để quen áp lực thời gian thật."]},{"id":"s2","title":"Cấu trúc đề thi tham khảo","bullets":["Khối phát âm và trọng âm thường khoảng bốn câu; ôn kỹ quy tắc đọc đuôi -s/-ed và nhận diện trọng âm ở từ hai đến bốn âm tiết.","Phần ngữ pháp kết hợp từ vựng chiếm phần lớn điểm số (khoảng mười lăm đến hai mươi câu), đòi hỏi hiểu ngữ cảnh chứ không học vẹt công thức.","Đọc hiểu gồm hai bài với năm và bảy câu; cần kỹ năng skim nắm ý chính rồi scan tìm bằng chứng cho từng lựa chọn.","Phần điền từ và sửa lỗi sai kiểm tra mạch văn, collocation và hòa hợp chủ vị — đọc cả câu/đoạn trước khi chọn đáp án."]},{"id":"s3","title":"Phân bổ thời gian hiệu quả","bullets":["Câu nhận diện nhanh (từ loại, cố định) nên xử lý dưới ba mươi giây mỗi câu để dành thời gian cho đoạn đọc hiểu.","Câu trung bình về ngữ pháp và paraphrase nên khoảng một phút; nếu kẹt hơn chín mươi giây, đánh dấu và quay lại sau.","Hai bài đọc hiểu nên dành mười đến mười lăm phút tổng; đọc chủ đề câu đầu, chủ điểm đoạn giữa và kết luận trước khi làm chi tiết.","Giữ năm phút cuối để kiểm tra phiếu, mã đề và các câu đã đánh dấu; không để trống ô vì đề trắc nghiệm không trừ điểm."]},{"id":"s4","title":"Chiến lược làm bài cơ bản","bullets":["Làm lần lượt các câu tự tin trước, gom câu khó để xử lý khi đã có cảm giác an toàn về thời gian.","Luôn chọn một đáp án; dùng loại trừ khi hai phương án còn lại gần nghĩa, đối chiếu lại manh mối trong câu/đoạn.","Với câu đồng nghĩa—trái nghĩa, gạch bỏ các lựa chọn sai ngữ cảnh trước khi so sánh hai đáp án còn lại.","Ghi nhớ một vài tín hiệu bẫy (not, except, only, unless) để tránh đọc vội và chọn nhầm ý phủ định."]},{"id":"s5","title":"Chuyên đề 1: Các thì (Tenses) - Phần 1","bullets":["Hiện tại đơn diễn tả thói quen và sự thật hiển nhiên; hiện tại tiếp diễn nhấn hành động đang diễn ra tại thời điểm nói hoặc quanh mốc thời gian.","Hiện tại hoàn thành liên kết quá khứ với hiện tại; since gắn mốc bắt đầu, for gắn khoảng thời gian kéo dài.","Dấu hiệu thời gian (always, yet, just, recently) và trạng từ tần suất giúp phân biệt nhanh giữa các thì gần nghĩa.","Khi câu có hai mốc thời gian, xác định hành động nào nền tảng và hành động nào xen vào để chọn đúng thì."]},{"id":"s6","title":"Chuyên đề 1: Các thì (Tenses) - Phần 2","bullets":["Quá khứ đơn mô tả hành động đã chấm dứt tại mốc rõ ràng; quá khứ hoàn thành nhấn hành động xảy ra trước một hành động khác trong quá khứ.","Tương lai đơn cho lịch trình hoặc quyết định tại chỗ; tương lai hoàn thành cho việc sẽ hoàn tất trước một mốc tương lai.","Phối hợp thì trong câu ghép và câu tường thuật đòi hỏi lùi thì nhất quán theo mốc thời gian của mệnh đề chính.","Ôn các cấu trúc by the time, before, after, until vì chúng thường kéo theo quá khứ hoàn thành hoặc tương lai hoàn thành."]},{"id":"s7","title":"Chuyên đề 2: Câu điều kiện (Conditionals)","bullets":["Loại một diễn tả điều có thể xảy ra ở hiện tại hoặc tương lai, dùng if + hiện tại và will/can/may ở mệnh đề chính.","Loại hai mô tả tình huống trái với thực tế hiện tại, dùng quá khứ đơn hoặc were trong if và would/could ở mệnh đề chính.","Loại ba diễn tả điều không thể đổi trong quá khứ, dùng if + had + PII và would have + PII để nói về hệ quả giả định.","Wish và unless thường đi kèm lùi thì tương tự câu điều kiện; cần phân biệt unless với if not để tránh nhầm nghĩa phủ định."]},{"id":"s8","title":"Chuyên đề 3: Câu bị động (Passive Voice)","bullets":["Cấu trúc nền tả là be + past participle, căn chỉnh thì của be theo chủ ngữ mới sau khi đổi từ chủ động.","Động từ khuyết thiếu (can, must, should) dùng bị động hoàn chỉnh với be + PII hoặc cấu trúc have something done tùy ngữ cảnh.","Các động từ tri giác (say, believe, think, report) thường xuất hiện dạng It is said that… hoặc S + be believed to… trong đề.","Chú ý hai tân ngữ và cách chuyển sang bị động với give/show/send để không đảo nhầm tác nhân và đối tượng."]},{"id":"s9","title":"Chuyên đề 4: Mệnh đề quan hệ (Relative Clauses)","bullets":["Who/whom cho người, which/that cho vật, whose cho sở hữu; that thường thay which trong mệnh đề xác định.","Mệnh đề không xác định có dấu phẩy tách ra, không dùng that; cần giữ đúng ngữ pháp sau dấu phẩy.","Rút gọn chủ động bằng V-ing và bị động bằng V3 khi đại từ quan hệ trùng chủ ngữ với mệnh đề phía trước.","Prep + whom/which đưa giới từ lên đầu trong văn phong trang trọng, thường gặp trong câu hỏi đảo hoặc điền từ."]},{"id":"s10","title":"Chuyên đề 5: Câu tường thuật (Reported Speech)","bullets":["Lùi thì khi động từ giới thiệu ở quá khứ (said/told/asked), trừ khi nội dung là chân lý hiện tại hoặc lịch cố định tương lai.","Đổi this→that, here→there, today→that day và các cụm tương tự để giữ mạch thời gian nhất quán.","Câu hỏi yes/no dùng if/whether; câu hỏi Wh- giữ từ hỏi và trật tự phụ thuộc sau động từ hỏi.","Mệnh lệnh và đề nghị chuyển sang told/asked + to V hoặc suggest + V-ing tùy động từ gốc."]},{"id":"s11","title":"Chuyên đề 6: So sánh (Comparisons)","bullets":["So sánh bằng as…as và not as/so…as; so sánh hơn với -er/more và nhất với -est/most, kèm much/even/far để nhấn mức độ.","Cấu trúc The more… the more… và The + so sánh nhất + noun cần đồng dạng song song hai về hai bên.","Một số tính từ bất quy tắc (good/better/best, bad/worse/worst) và danh từ đếm được/ không đếm được với less/fewer.","Tránh lặp so sánh kép sai (double comparative) và đảm bảo chỉ so sánh đúng nhóm từ (tính từ với tính từ, trạng từ với trạng từ)."]},{"id":"s12","title":"Chuyên đề 7: Đảo ngữ (Inversion)","bullets":["Never, rarely, seldom, hardly… when, no sooner… than đòi hỏi đảo trợ động từ hoặc đảo be lên trước chủ ngữ.","Only after, only when, not only… but also có thể kích hoạt đảo một phần; cần giữ đúng dạng trợ động từ khớp thì.","Đảo với So + adj + be và Such + noun phrase + be để nhấn mạnh mức độ, thường gặp trong viết học thuật và paraphrase.","Đảo trong câu điều kiện loại ba với Had I known… ít gặp hơn nhưng vẫn xuất hiện trong câu hỏi khó."]},{"id":"s13","title":"Chuyên đề 8: Câu hỏi đuôi (Tag Questions)","bullets":["Đại từ trong tag trùng chủ ngữ câu chính; trợ động từ phản chiếu thì và sự khẳng định/phủ định của mệnh đề trước.","Trường hợp đặc biệt với I am (aren't I?), Let's (shall we?), nobody/everyone (they) cần học thuộc mẫu.","Câu mệnh lệnh dùng will you / won't you tùy sắc thái; câu phủ định mời lịch sự dùng will you.","Ngữ điệu hỏi thật hay hỏi xác nhận phụ thuộc vào intonation; trong trắc nghiệm tập trung vào dạng từ đúng."]},{"id":"s14","title":"Chuyên đề 9: Danh động từ & Động từ nguyên mẫu","bullets":["Một số động từ chỉ bám theo V-ing (enjoy, avoid, mind), một số chỉ to V (agree, decide, hope, refuse).","Động từ đổi nghĩa theo V-ing và to V như stop, remember, try, need — cần ví dụ minh họa cho từng nghĩa.","Cấu trúc can't help, feel like, it's no use + V-ing thường là bẫy nếu chỉ học danh sách tĩnh.","Sau giới từ luôn là V-ing; sau make/let/help có quy tắc bare infinitive riêng cần nhớ kỹ."]},{"id":"s15","title":"Chuyên đề 10: Giới từ (Prepositions)","bullets":["Thời gian in/on/at cho khoảng, ngày cụ thể và mốc giờ; at night nhưng in the morning trừ khi có this/last/every.","Nơi chốn at/in/on the corner, arrive at/in, depend on, afraid of — học theo cụm collocation hơn là dịch từng từ.","Tính từ + giới từ cố định (interested in, good at, keen on) là dạng điền từ rất thường gặp.","Phân biệt between/among, by/until, during/for để tránh lỗi logic thời gian trong đoạn điền từ."]},{"id":"s16","title":"Chuyên đề 11: Liên từ (Conjunctions)","bullets":["Because + mệnh đề khác because of + cụm danh từ; although + mệnh đề khác despite/in spite of + V-ing hoặc noun.","However, therefore, moreover là discourse markers — chú ý dấu câu và vị trí trong câu ghép.","Neither… nor và either… or bắt buộc hòa hợp chủ vị theo thành phần gần động từ nhất.","Not only… but also có thể kích hoạt đảo ngữ khi not only mở đầu câu."]},{"id":"s17","title":"Chủ điểm từ vựng 1: Giáo dục","bullets":["Curriculum và syllabus chỉ khung chương trình; literacy nhấn khả năng đọc viết cơ bản và digital literacy.","Compulsory education, prestigious school, graduate with honours là cụm hay gặp trong đoạn về học đường.","Distance learning và lifelong learning thường xuất hiện trong bài đọc về công nghệ và cơ hội nghề nghiệp.","Paraphrase qualification, certificate, enrollment để nhanh chóng khớp đáp án đồng nghĩa trong đề."]},{"id":"s18","title":"Chủ điểm từ vựng 2: Môi trường","bullets":["Emission, carbon footprint và renewable energy là trục từ vựng của đoạn về biến đổi khí hậu.","Biodiversity, habitat loss, conserve và restore thường đi cùng trong bài về bảo tồn.","Pollution levels, ozone layer, sustainable development tạo mạch liên kết paraphrase dễ nhận ra.","Collocation cut emissions, raise awareness, tackle climate crisis hay xuất hiện dạng gap-fill."]},{"id":"s19","title":"Chủ điểm từ vựng 3: Công nghệ & AI","bullets":["Artificial intelligence, machine learning và automation là nhóm từ lõi cho bài công nghệ.","Cybersecurity, data breach, privacy concern thường đối lập với convenience và innovation.","Upgrade firmware, seamless interface, user experience là cụm collocation trong quảng cáo sản phẩm.","Đề có thể hỏi nghĩa bóng của disrupt, deploy, integrate trong ngữ cảnh doanh nghiệp."]},{"id":"s20","title":"Chủ điểm từ vựng 4: Xã hội & Sức khỏe","bullets":["Prejudice, discrimination và inequality thường cùng chủ đề công bằng xã hội.","Ethical dilemma, resilient community, public health policy tạo mạch học thuật dễ skim.","Pandemic, immune system, mental well-being là cụm sức khỏe tổng hợp hay gặp.","Integration, marginalize và vulnerable groups thường xuất hiện trong đoạn tranh luận."]},{"id":"s21","title":"Dạng bài: Phát âm (Phonetics)","bullets":["Đuôi -s/-es phụ thuộc âm cuối (/s/, /z/, /ʃ/…); đuôi -ed có /t/, /d/, /ɪd/ — luyện đọc to nhóm từ.","Nguyên âm dài/ngắn (ship/sheep, full/fool) là bẫy phổ biến trong câu hỏi phát âm khác nhau.","Nối âm và ngọng âm nhẹ trong cụm từ giúp nghe đúng dạng bài listening minh họa (nếu có).","Ghi chú IPA ngắn bên cạnh từ khó khi ôn để não bộ nhận diện nhanh hơn trong phòng thi."]},{"id":"s22","title":"Dạng bài: Trọng âm (Stress)","bullets":["Hai âm tiết thường nhấn âm đầu nếu là danh từ/ tính từ Germanic, trừ một loạt ngoại lệ (hotel, police…).","Ba âm tiết trở lên cần nhớ quy tắc hậu tố -tion, -ic, -ity, -ive làm lệch trọng âm.","Danh từ ghép và từ có tiền tố re-, de-, pre- có quy tắc nhấn riêng; ôn theo nhóm.","Stress ảnh hưởng nghĩa từ (record động từ/danh từ) — đọc kỹ loại từ trong câu hỏi."]},{"id":"s23","title":"Dạng bài: Tìm lỗi sai (Error Correction)","bullets":["Rà soát chủ vị và danh từ tập hợp (each of, one of the…) vì đây là lỗi tần suất cao.","Đại từ, tính từ sở hữu và mạch tham chiếu (this/these) thường sai khi đoạn dài.","Song song cấu trúc (not only A but also B) đòi hỏi cùng loại từ/cụm sau cả hai nhánh.","Đọc cả câu sau khi sửa để đảm bảo không tạo lỗi mới về thì hoặc giới từ."]},{"id":"s24","title":"Dạng bài: Đồng nghĩa - Trái nghĩa","bullets":["Luôn neo nghĩa vào câu gốc; một từ có thể đồng nghĩa trong ngữ cảnh này nhưng không trong ngữ cảnh khác.","Đề thường ghi rõ CLOSEST in meaning hoặc OPPOSITE — khoanh đúng yêu cầu trước khi đọc đáp án.","Các cặp near-synonym (say/tell, rise/arise) là bẫy khi chỉ nhìn nghĩa từ điển.","Dùng elimination với các lựa chọn quá rộng hoặc quá hẹp so với ngữ cảnh."]},{"id":"s25","title":"Dạng bài: Điền từ vào đoạn văn","bullets":["Xác định chỗ trống cần danh từ, động từ, tính từ hay trạng từ bằng từ loại xung quanh và mạch nghĩa.","Collocation quyết định đáp án đúng nhiều hơn nghĩa đơn lẻ; đọc cả cụm hai ba chữ trước và sau.","Liên kết đoạn (however, for example, as a result) có thể là ô trống cần discourse marker.","Sau khi điền xong, đọc lại đoạn như một bài hoàn chỉnh để kiểm tra ngữ pháp và logic."]},{"id":"s26","title":"Dạng bài: Đọc hiểu - Ý chính","bullets":["Skimming — đọc tiêu đề, câu chủ đề đoạn đầu, chủ điểm đoạn giữa và câu kết để nắm thesis.","Ý chính không phải chi tiết nhỏ nhất; tránh chọn đáp án chỉ đúng một ví dụ phụ.","Tác giả có thể nêu vấn đề rồi đưa giải pháp; nhận diện pivot words (however, yet) để không lẫn hai phần.","Khi hai đáp án đều hợp lý, chọn ý bao quát toàn bài hơn là ý chỉ đúng một đoạn."]},{"id":"s27","title":"Dạng bài: Đọc hiểu - Chi tiết","bullets":["Scanning — khoanh từ khóa trong đề rồi tìm đoạn có synonym hoặc paraphrase trong bài.","Đối chiếu số liệu, tên riêng, ngày tháng chính xác từng ký tự để tránh bẫy almost-true.","Câu hỏi NOT/EXCEPT đòi hỏi kiểm tra từng phương án một cách có hệ thống.","Gạch chân manh mối trong bài ngay khi đọc để tiết kiệm thời gian quay lại."]},{"id":"s28","title":"Dạng bài: Đọc hiểu - Suy luận & Đại từ","bullets":["Suy luận (infer) cần bằng chứng gián tiếp; không chọn đáp án quá tuyệt đối nếu bài không khẳng định.","Đại từ it/they/this thay thế cho cụm danh từ nào — đọc câu trước và sau hai ba câu.","Thái độ tác giả (neutral, critical, supportive) thường nằm ở tính từ mang sắc thái và modal verbs.","Paraphrase câu hỏi sang tiếng Việt nhanh giúp não bộ khớp ý với đoạn tiếng Anh."]},{"id":"s29","title":"Dạng bài: Viết lại câu","bullets":["Chủ động ↔ bị động giữ nghĩa và thì; chú ý by-agent có thể bị lược trong đề.","Tường thuật lời nói trực tiếp sang gián tiếp với động từ said/told/asked và lùi thì.","Câu so sánh, câu ước, câu điều kiện thường giữ nguyên nghĩa nhưng đổi cấu trúc từ khóa gợi ý.","Giữ các danh từ riêng và số liệu không đổi trừ khi đề yêu cầu thay thế cụ thể."]},{"id":"s30","title":"Dạng bài: Kết hợp hai câu","bullets":["Dùng mệnh đề quan hệ để gộp khi hai câu cùng chủ thể hoặc có từ lặp lại rõ ràng.","Liên từ và trạng từ nối (however, therefore, because) giúp giữ logic nhân-quả khi gộp.","Rút gọn bằng phân từ (Having finished…, Seen from…) nếu đề cho phép và đúng chủ thể.","Đọc câu ghép sau cùng để đảm bảo không thừa/khuyết thành phần so với hai câu gốc."]},{"id":"s31","title":"Những bẫy thường gặp trong đề thi","bullets":["Make vs do với collocation cố định (make progress, do homework) — không dịch word-by-word từ tiếng Việt.","Say/tell/speak/talk khác nhau về giới từ và tân ngữ; tell cần người nghe xác định.","Tính từ -ing/-ed mô tả bản chất vs cảm xúc (boring/bored); chủ ngữ là sự vật hay con người quyết định dạng.","Little/a little, few/a few thay đổi nghĩa hoàn toàn; much/many phụ thuộc danh từ đếm được."]},{"id":"s32","title":"Cụm động từ phổ biến (Phrasal Verbs)","bullets":["Take off (cất cánh), take on (đảm nhận), take after (giống) — học theo cụm ví dụ ngắn.","Give up (từ bỏ), give in (nhượng bộ), give away (tiết lộ/cho không) dễ nhầm nếu chỉ nhớ một nghĩa.","Go on (tiếp tục), go out (tắt/ra ngoài), go over (ôn lại) thường trong cloze có ngữ cảnh.","Viết một câu story nhỏ dùng 8–10 phrasal verbs để não bộ nhớ theo bối cảnh."]},{"id":"s33","title":"Cụm từ cố định (Collocations)","bullets":["Make a decision, make an effort; do business, do harm — gom nhóm theo động từ trung tâm.","Take responsibility, take part in, pay attention to, run a risk là cụm academic writing.","Strong collocations (launch a campaign, address an issue) hay xuất hiện trong đoạn đọc nửa học thuật.","Tránh dịch từng từ sang tiếng Việt khiến chọn sai đáp án gần nghĩa."]},{"id":"s34","title":"Thành ngữ thường gặp (Idioms)","bullets":["Piece of cake (dễ), once in a blue moon (hiếm) — nắm nghĩa bóng, không dịch literal.","Actions speak louder than words; break a leg (chúc may) là cụm giao tiếp đa dạng.","Under the weather (khỏe kém), hit the books (ôn bài) thường trong bài informal.","Học idiom kèm ví dụ một dòng để nhớ ngữ cảnh sử dụng."]},{"id":"s35","title":"Luyện tập: Đọc biểu đồ & bảng biểu","bullets":["Từ xu hướng rise/increase, fall/decrease, remain stable, fluctuate dùng mô tả đường và cột.","So sánh phần trăm và số tuyệt đối — chú ý đơn vị (million vs thousand) trong đề.","Mô tả tóm tắt nên có chủ đề + điểm nổi bật + xu hướng tổng thể trong hai ba câu.","Luyện viết một đoạn mô tả chart trong năm phút để quen cấu trúc topic sentence."]},{"id":"s36","title":"Tâm lý phòng thi","bullets":["Gặp câu khó — hít thở, bỏ qua tạm thời và làm các câu tự tin để lấy đà.","Tập trung vào đề bản in, không so bánh với bạn bên cạnh để tránh loãng ý.","Chia nhỏ thời gian theo từng phần đề; nhắc nhở bản thân mỗi mười lăm phút.","Tự khẳng định ngắn trước giờ vào phòng (đã chuẩn bị đủ) giúp giảm cortisol."]},{"id":"s37","title":"Kỹ thuật tô phiếu đáp án","bullets":["Tô đậm, kín ô tròn; tránh gạch chéo nhiều lần gây máy không đọc được.","Chiến lược làm theo trang hoặc theo phần — chọn một và nhất quán để không sót ô.","Kiểm tra mã đề, số báo danh và các câu đã đánh dấu review trong năm phút cuối.","Mang theo tẩy sạch và bút chì HB/2B theo quy định điểm thi."]},{"id":"s38","title":"Ôn tập nước rút","bullets":["Rà lại sổ tay lỗi sai cá nhân thay vì học mới nội dung rộng trong tuần cuối.","Làm đề theo giờ thật, sau đó phân loại lỗi theo dạng bài để ôn có trọng tâm.","Ngủ đủ bảy tiếng trước ngày thi; não xử lý ngôn ngữ kém hơn khi thiếu ngủ.","Giữ nhịp ăn uống quen thuộc, tránh đồ lạ gây khó chịu dạ dày."]},{"id":"s39","title":"Checklist trước ngày thi","bullets":["Chuẩn bị giấy tờ tùy thân, thiệp báo danh, bút chì, tẩy, đồng hồ đeo tay (nếu được phép).","Đi khảo sát địa điểm thi trước một lần để ước thời gian di chuyển và chỗ gửi xe.","Đặt báo thức dự phòng; sạc điện thoại nhưng nhớ quy định cất máy khi vào phòng.","Tối trước ngày thi chỉ ôn light review — không học khuya làm giảm tập trung."]},{"id":"s40","title":"Lời chúc & Động lực","bullets":["Bạn đã đầu tư thời gian và công sức — hãy tin vào quá trình và bình tĩnh thể hiện.","Mỗi đề thi chỉ là một snapshot; quan trọng là chiến lược dài hơi và thái độ học hỏi.","Giữ nhịp thở đều khi chuông khai mạc; đọc kỹ phần hướng dẫn trước khi lật đề.","Chúc bạn đạt kết quả xứng đáng với nỗ lực và mở được cánh cửa mong muốn."]}]};
